import{_ as i,C as o,o as a,c as l,a2 as e,b as n,w as r,a as s,E as f,a3 as k}from"./chunks/framework.Crpw6aS5.js";const u=JSON.parse('{"title":"Kafka 消息队列","description":"","frontmatter":{"title":"Kafka 消息队列","module":"mq-kafka","difficulty":"intermediate","interviewFrequency":"high","tags":["Kafka","消息队列","流处理","面试高频"],"codeExample":"04-middleware/mq-kafka-examples/src/main/java/com/example/mq/kafka/","relatedEntries":["/4-middleware/4.1-mq-rabbitmq/","/2-framework/2.2-springboot/"],"prerequisites":["/2-framework/2.2-springboot/","/1-java-core/1.3-concurrent/"],"estimatedTime":"30min"},"headers":[],"relativePath":"4-middleware/4.2-mq-kafka/00-index.md","filePath":"4-middleware/4.2-mq-kafka/00-index.md","lastUpdated":null}'),h={name:"4-middleware/4.2-mq-kafka/00-index.md"};function b(m,t,c,E,p,A){const d=o("Mermaid");return a(),l("div",null,[t[1]||(t[1]=e('<h1 id="kafka-消息队列" tabindex="-1">Kafka 消息队列 <a class="header-anchor" href="#kafka-消息队列" aria-label="Permalink to &quot;Kafka 消息队列&quot;">​</a></h1><h2 id="概念说明" tabindex="-1">概念说明 <a class="header-anchor" href="#概念说明" aria-label="Permalink to &quot;概念说明&quot;">​</a></h2><p>Apache Kafka 是一个<strong>分布式流处理平台</strong>，最初由 LinkedIn 开发，后成为 Apache 顶级项目。Kafka 以<strong>高吞吐量、低延迟、高可用</strong>著称，广泛用于日志收集、数据管道、流处理、事件驱动架构等场景。它是 Java 后端面试中<strong>消息队列方向的核心考察模块</strong>，从分区与副本机制到消费者组 Rebalance，再到 Exactly-Once 语义，都是面试高频考点。</p><p>本模块从 Kafka 的架构原理出发，深入讲解消息可靠性、高级特性以及 Spring Boot 集成，帮助你系统掌握 Kafka 在面试和工作中的关键技术。</p><blockquote><p>⚠️ 需要 Kafka 环境的示例，请先启动 Docker：<code>docker compose -f docker/docker-compose.mq.yml up -d</code></p></blockquote><h2 id="知识点列表" tabindex="-1">知识点列表 <a class="header-anchor" href="#知识点列表" aria-label="Permalink to &quot;知识点列表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>序号</th><th>知识点</th><th>难度</th><th>面试频率</th><th>文档链接</th></tr></thead><tbody><tr><td>1</td><td>Kafka 架构与原理</td><td>⭐⭐⭐</td><td>🔥🔥🔥</td><td><a href="./01-kafka.html">kafka</a></td></tr><tr><td>2</td><td>消息可靠性与顺序性</td><td>⭐⭐⭐</td><td>🔥🔥🔥</td><td><a href="./02-kafka-reliability.html">kafka-reliability</a></td></tr><tr><td>3</td><td>高级特性</td><td>⭐⭐⭐</td><td>🔥🔥🔥</td><td><a href="./03-kafka-advanced.html">kafka-advanced</a></td></tr><tr><td>4</td><td>Spring Boot 集成</td><td>⭐⭐</td><td>🔥🔥</td><td><a href="./04-kafka-spring.html">kafka-spring</a></td></tr><tr><td>5</td><td>Kafka 面试指南</td><td>⭐⭐⭐</td><td>🔥🔥🔥</td><td><a href="./99-interview.html">interview</a></td></tr></tbody></table><h2 id="推荐学习顺序" tabindex="-1">推荐学习顺序 <a class="header-anchor" href="#推荐学习顺序" aria-label="Permalink to &quot;推荐学习顺序&quot;">​</a></h2>',8)),(a(),n(k,null,{default:r(()=>[f(d,{id:"mermaid-131",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20A%5B%221.%20%E6%9E%B6%E6%9E%84%E4%B8%8E%E5%8E%9F%E7%90%86%3Cbr%2F%3EBroker%2FTopic%2FPartition%2FReplica%22%5D%20--%3E%20B%5B%222.%20%E6%B6%88%E6%81%AF%E5%8F%AF%E9%9D%A0%E6%80%A7%E4%B8%8E%E9%A1%BA%E5%BA%8F%E6%80%A7%3Cbr%2F%3Eacks%2FISR%2FExactly-Once%22%5D%0A%20%20%20%20B%20--%3E%20C%5B%223.%20%E9%AB%98%E7%BA%A7%E7%89%B9%E6%80%A7%3Cbr%2F%3E%E5%88%86%E5%8C%BA%E7%AD%96%E7%95%A5%2FRebalance%2F%E4%BA%8B%E5%8A%A1%22%5D%0A%20%20%20%20A%20--%3E%20D%5B%224.%20Spring%20Boot%20%E9%9B%86%E6%88%90%3Cbr%2F%3EKafkaTemplate%2F%40KafkaListener%22%5D%0A%20%20%20%20B%20--%3E%20D%0A%20%20%20%20C%20--%3E%20E%5B%225.%20%E9%9D%A2%E8%AF%95%E6%8C%87%E5%8D%97%E6%B1%87%E6%80%BB%22%5D%0A%20%20%20%20D%20--%3E%20E%0A%0A%20%20%20%20style%20A%20fill%3A%23e1f5fe%0A%20%20%20%20style%20B%20fill%3A%23e1f5fe%0A%20%20%20%20style%20C%20fill%3A%23fff3e0%0A%20%20%20%20style%20D%20fill%3A%23f3e5f5%0A%20%20%20%20style%20E%20fill%3A%23e8f5e9%0A"})]),fallback:r(()=>[...t[0]||(t[0]=[s(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=e('<p><strong>学习路线说明</strong>：</p><ul><li>🔵 <strong>核心原理层</strong>（1-2）：架构设计和消息可靠性是 Kafka 的基石</li><li>🟠 <strong>高级特性层</strong>（3）：分区策略、Rebalance、事务是面试高频考点</li><li>🟣 <strong>集成应用层</strong>（4）：Spring Boot 集成是工作中的日常使用</li><li>🟢 <strong>面试汇总</strong>（5）：高频面试题和追问链路</li></ul><h2 id="kafka-vs-rabbitmq-对比" tabindex="-1">Kafka vs RabbitMQ 对比 <a class="header-anchor" href="#kafka-vs-rabbitmq-对比" aria-label="Permalink to &quot;Kafka vs RabbitMQ 对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>Kafka</th><th>RabbitMQ</th></tr></thead><tbody><tr><td>消息模型</td><td>发布订阅（Topic + Partition）</td><td>队列模型（点对点 + 发布订阅）</td></tr><tr><td>吞吐量</td><td>百万级 QPS</td><td>万级 QPS</td></tr><tr><td>延迟</td><td>毫秒级</td><td>微秒级</td></tr><tr><td>消息存储</td><td>磁盘顺序写，持久化保留</td><td>内存为主，消费即删除</td></tr><tr><td>消息回溯</td><td>支持（基于 Offset 回溯）</td><td>不支持</td></tr><tr><td>消息顺序</td><td>单分区有序</td><td>单队列有序</td></tr><tr><td>消费模式</td><td>Pull（消费者主动拉取）</td><td>Push（Broker 推送）</td></tr><tr><td>协议</td><td>自定义协议</td><td>AMQP</td></tr><tr><td>适用场景</td><td>日志收集、流处理、大数据管道</td><td>业务解耦、异步通知、延迟任务</td></tr></tbody></table><p><strong>选型建议</strong>：</p><ul><li>日志收集、数据管道、流处理 → <strong>Kafka</strong></li><li>业务消息（订单、通知、异步任务）→ <strong>RabbitMQ</strong></li><li>对吞吐量要求极高的场景 → <strong>Kafka</strong></li><li>对延迟敏感的场景 → <strong>RabbitMQ</strong></li><li>需要消息回溯的场景 → <strong>Kafka</strong></li></ul><h2 id="相关模块链接" tabindex="-1">相关模块链接 <a class="header-anchor" href="#相关模块链接" aria-label="Permalink to &quot;相关模块链接&quot;">​</a></h2><ul><li><a href="/4-middleware/4.1-mq-rabbitmq/">RabbitMQ 消息队列</a> — 另一种主流消息中间件</li><li><a href="/2-framework/2.2-springboot/">Spring Boot</a> — Kafka 与 Spring Boot 集成</li><li><a href="/5-distributed/5.1-distributed/">分布式系统</a> — 消息最终一致性方案</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://kafka.apache.org/documentation/" target="_blank" rel="noreferrer">Apache Kafka 官方文档</a></li><li><a href="https://book.douban.com/subject/27665114/" target="_blank" rel="noreferrer">《Kafka 权威指南》</a></li><li><a href="https://book.douban.com/subject/30437872/" target="_blank" rel="noreferrer">《深入理解 Kafka》— 朱忠华</a></li></ul>',10))])}const B=i(h,[["render",b]]);export{u as __pageData,B as default};
